class BCHEncoder:
    def __init__(self, message_bits=256, error_allowance=330):
        self.k = message_bits
        self.t = error_allowance
        self.m = 14 # Because we are using GF(2^12)        
        # In an enterprise cryptosystem, the Generator Polynomial is mathematically 
        # derived from the Galois Field roots and hardcoded as a constant 1D array.
        # Generating it dynamically takes massive CPU power, so we load it once.
        self.generator_poly = self._load_generator_polynomial()
        self.parity_length = len(self.generator_poly) - 1 
        self.n = self.k + self.parity_length

